    80→function TmsContent() {
    81→  const [applicationName, setApplicationName] = useState<string>('');
    82→  const [availableApplications, setAvailableApplications] = useState<string[]>([]);
    83→  const [availableLocales, setAvailableLocales] = useState<string[]>([]);
    84→  // Unified structure: single TranslationsModel where each translation has all locales
    85→  const [unifiedTranslations, setUnifiedTranslations] = useState<TranslationsModel | null>(null);
    86→  const [expandedComponents, setExpandedComponents] = useState<Set<string>>(new Set());
    87→  const [loading, setLoading] = useState(true);
    88→  const [saving, setSaving] = useState(false);
    89→  const [error, setError] = useState('');
    90→  
    91→  // Dialog states
    92→  const [createAppDialogOpen, setCreateAppDialogOpen] = useState(false);
    93→  const [createComponentDialogOpen, setCreateComponentDialogOpen] = useState(false);
    94→  const [createTranslationDialogOpen, setCreateTranslationDialogOpen] = useState(false);
    95→  const [newAppName, setNewAppName] = useState('');
    96→  const [newComponentName, setNewComponentName] = useState('');
    97→  const [newComponentDescription, setNewComponentDescription] = useState('');
    98→  const [newComponentPath, setNewComponentPath] = useState<string[]>([]);
    99→  const [newTranslationName, setNewTranslationName] = useState('');
   100→  const [newTranslationDescription, setNewTranslationDescription] = useState('');
   101→  const [newTranslationPath, setNewTranslationPath] = useState<string[]>([]);
   102→  const [selectedLocales, setSelectedLocales] = useState<string[]>(['en']);
   103→
   104→  const loadApplications = async () => {
   105→    try {
   106→      const apps = await apiClient.getAllApplications();
   107→      setAvailableApplications(apps);
   108→      if (!applicationName && apps.length > 0) {
   109→        setApplicationName(apps[0]);
   110→      }
   111→    } catch (err) {
   112→      console.error('Failed to load applications:', err);
   113→    }
   114→  };
   115→
   116→  const loadLocales = async () => {
   117→    try {
   118→      const locales = await apiClient.getAllLocales();
   119→      setAvailableLocales(locales);
   120→    } catch (err) {
   121→      console.error('Failed to load locales:', err);
   122→    }
   123→  };
   124→
   125→  // Merge translations from all locales into unified structure
   126→  const mergeTranslations = (translationsByLocale: Map<string, TranslationsModel>): TranslationsModel | null => {
   127→    if (translationsByLocale.size === 0) return null;
   128→
   129→    const firstTranslation = Array.from(translationsByLocale.values())[0];
   130→    if (!firstTranslation) return null;
   131→
   132→    const merged: TranslationsModel = {
   133→      applicationName: firstTranslation.applicationName,
   134→      components: [],
   135→      version: firstTranslation.version,
   136→    };
   137→
   138→    // Helper to merge components recursively
   139→    const mergeComponents = (componentsByLocale: TranslationComponent[][]): TranslationComponent[] => {
   140→      if (componentsByLocale.length === 0) return [];
   141→
   142→      const componentMap = new Map<string, TranslationComponent>();
   143→
   144→      componentsByLocale.forEach((components) => {
   145→        const processComponent = (comp: TranslationComponent, path: string[] = []) => {
   146→          const key = [...path, comp.name].join('.');
   147→          
   148→          if (!componentMap.has(key)) {
   149→            componentMap.set(key, {
   150→              name: comp.name,
   151→              description: comp.description,
   152→              components: [],
   153→              translations: [],
   154→            });
   155→          }
   156→
   157→          const mergedComp = componentMap.get(key)!;
   158→
   159→          // Merge translations
   160→          if (comp.translations) {
   161→            comp.translations.forEach((trans) => {
   162→              let mergedTrans = mergedComp.translations?.find(t => t.name === trans.name);
   163→              
   164→              if (!mergedTrans) {
   165→                mergedTrans = {
   166→                  name: trans.name,
   167→                  description: trans.description,
   168→                  version: trans.version,
   169→                  locales: [],
   170→                };
   171→                mergedComp.translations = [...(mergedComp.translations || []), mergedTrans];
   172→              }
   173→
   174→              // Merge all locales from this translation
   175→              trans.locales.forEach((locale) => {
   176→                const existingIndex = mergedTrans!.locales.findIndex(l => l.code === locale.code);
   177→                if (existingIndex >= 0) {
   178→                  // Update value
   179→                  mergedTrans!.locales[existingIndex] = { code: locale.code, value: locale.value };
   180→                } else {
   181→                  // Add new locale
   182→                  mergedTrans!.locales.push({ code: locale.code, value: locale.value });
   183→                }
   184→              });
   185→            });
   186→          }
   187→
   188→          // Process nested components
   189→          if (comp.components) {
   190→            comp.components.forEach(subComp => processComponent(subComp, [...path, comp.name]));
   191→          }
   192→        };
   193→
   194→        components.forEach(comp => processComponent(comp));
   195→      });
   196→
   197→      // Build tree structure from map
   198→      const buildTree = (path: string[] = []): TranslationComponent[] => {
   199→        const result: TranslationComponent[] = [];
   200→        const pathStr = path.join('.');
   201→        
   202→        componentMap.forEach((comp, key) => {
   203→          const compPath = key.split('.');
   204→          const parentPath = compPath.slice(0, -1);
   205→          const parentPathStr = parentPath.join('.');
   206→          
   207→          if (parentPathStr === pathStr) {
   208→            result.push({
   209→              ...comp,
   210→              components: buildTree(compPath),
   211→            });
   212→          }
   213→        });
   214→
   215→        return result;
   216→      };
   217→
   218→      return buildTree();
   219→    };
   220→
   221→    const allComponents = Array.from(translationsByLocale.values()).map(t => t.components);
   222→    merged.components = mergeComponents(allComponents);
   223→    return merged;
   224→  };
   225→
   226→  const loadTranslations = async () => {
   227→    if (!applicationName) {
   228→      setLoading(false);
   229→      return;
   230→    }
   231→
   232→    setLoading(true);
   233→    setError('');
   234→    try {
   235→      const translationsByLocale = new Map<string, TranslationsModel>();
   236→      
   237→      // Load all locales
   238→      await Promise.all(
   239→        availableLocales.map(async (locale) => {
   240→          try {
   241→            const data = await apiClient.getTranslations(locale, applicationName);
   242→            translationsByLocale.set(locale, data);
   243→          } catch (err) {
   244→            console.error(`Failed to load translations for locale ${locale}:`, err);
   245→          }
   246→        })
   247→      );
   248→
   249→      // Merge into unified structure
   250→      const merged = mergeTranslations(translationsByLocale);
   251→      setUnifiedTranslations(merged);
   252→    } catch (err) {
   253→      setError(
   254→        err instanceof Error ? err.message : 'Failed to load translations',
   255→      );
   256→    } finally {
   257→      setLoading(false);
   258→    }
   259→  };
   260→
   261→  useEffect(() => {
   262→    loadApplications();
   263→    loadLocales();
   264→  }, []);
   265→
   266→  useEffect(() => {
   267→    if (availableLocales.length > 0) {
   268→      loadTranslations();
   269→    }
   270→  }, [applicationName, availableLocales]);
   271→
   272→  // Split unified structure back into per-locale structures for API
   273→  const splitByLocale = (unified: TranslationsModel): Map<string, TranslationsModel> => {
   274→    const result = new Map<string, TranslationsModel>();
   275→    const allLocales = new Set<string>();
   276→
   277→    // Collect all locales from all translations
   278→    const collectLocales = (components: TranslationComponent[]) => {
   279→      components.forEach(comp => {
   280→        if (comp.translations) {
   281→          comp.translations.forEach(trans => {
   282→            trans.locales.forEach(locale => {
   283→              allLocales.add(locale.code);
   284→            });
   285→          });
   286→        }
   287→        if (comp.components) {
   288→          collectLocales(comp.components);
   289→        }
   290→      });
   291→    };
   292→
   293→    collectLocales(unified.components);
   294→
   295→    // Create structure for each locale
   296→    allLocales.forEach(localeCode => {
   297→      const splitComponent = (comp: TranslationComponent): TranslationComponent => {
   298→        const splitTrans: TranslationItem[] = [];
   299→        
   300→        if (comp.translations) {
   301→          comp.translations.forEach(trans => {
   302→            const localeItem = trans.locales.find(l => l.code === localeCode);
   303→            if (localeItem) {
   304→              splitTrans.push({
   305→                name: trans.name,
   306→                description: trans.description,
   307→                version: trans.version,
   308→                locales: [localeItem],
   309→              });
   310→            }
   311→          });
   312→        }
   313→
   314→        return {
   315→          name: comp.name,
   316→          description: comp.description,
   317→          components: comp.components?.map(splitComponent),
   318→          translations: splitTrans.length > 0 ? splitTrans : undefined,
   319→        };
   320→      };
   321→
   322→      result.set(localeCode, {
   323→        applicationName: unified.applicationName,
   324→        components: unified.components.map(splitComponent),
   325→        version: unified.version,
   326→      });
   327→    });
   328→
   329→    return result;
   330→  };
   331→
   332→  const updateTranslationValue = (
   333→    componentPath: string[],
   334→    translationName: string,
   335→    localeCode: string,
   336→    value: string,
   337→  ) => {
   338→    if (!unifiedTranslations) return;
   339→
   340→    setUnifiedTranslations((prev) => {
   341→      if (!prev) return prev;
   342→
   343→      const updateInComponents = (components: TranslationComponent[], path: string[]): TranslationComponent[] => {
   344→        if (path.length === 0) {
   345→          return components.map(comp => {
   346→            if (!comp.translations) return comp;
   347→            
   348→            return {
   349→              ...comp,
   350→              translations: comp.translations.map(trans => {
   351→                if (trans.name !== translationName) return trans;
   352→                
   353→                const localeIndex = trans.locales.findIndex(l => l.code === localeCode);
   354→                if (localeIndex >= 0) {
   355→                  return {
   356→                    ...trans,
   357→                    locales: trans.locales.map((loc, idx) => 
   358→                      idx === localeIndex ? { ...loc, value } : loc
   359→                    ),
   360→                  };
   361→                } else {
   362→                  return {
   363→                    ...trans,
   364→                    locales: [...trans.locales, { code: localeCode, value }],
   365→                  };
   366→                }
   367→              }),
   368→            };
   369→          });
   370→        }
   371→
   372→        const [current, ...rest] = path;
   373→        return components.map(comp => {
   374→          if (comp.name !== current) return comp;
   375→
   376→          return {
   377→            ...comp,
   378→            components: comp.components ? updateInComponents(comp.components, rest) : undefined,
   379→            translations: rest.length === 0 && comp.translations
   380→              ? comp.translations.map(trans => {
   381→                  if (trans.name !== translationName) return trans;
   382→                  
   383→                  const localeIndex = trans.locales.findIndex(l => l.code === localeCode);
   384→                  if (localeIndex >= 0) {
   385→                    return {
   386→                      ...trans,
   387→                      locales: trans.locales.map((loc, idx) => 
   388→                        idx === localeIndex ? { ...loc, value } : loc
   389→                      ),
   390→                    };
   391→                  } else {
   392→                    return {
   393→                      ...trans,
   394→                      locales: [...trans.locales, { code: localeCode, value }],
   395→                    };
   396→                  }
   397→                })
   398→              : comp.translations,
   399→          };
   400→        });
   401→      };
   402→
   403→      return {
   404→        ...prev,
   405→        components: updateInComponents(prev.components, componentPath),
   406→      };
   407→    });
   408→  };
   409→
   410→  const addLocaleToTranslation = (
   411→    componentPath: string[],
   412→    translationName: string,
   413→    localeCode: string,
   414→  ) => {
   415→    if (!unifiedTranslations) return;
   416→
   417→    setUnifiedTranslations((prev) => {
   418→      if (!prev) return prev;
   419→
   420→      const addLocaleInComponents = (components: TranslationComponent[], path: string[]): TranslationComponent[] => {
   421→        if (path.length === 0) {
   422→          return components.map(comp => {
   423→            if (!comp.translations) return comp;
   424→            
   425→            return {
   426→              ...comp,
   427→              translations: comp.translations.map(trans => {
   428→                if (trans.name === translationName) {
   429→                  const hasLocale = trans.locales.some(l => l.code === localeCode);
   430→                  if (!hasLocale) {
   431→                    return {
   432→                      ...trans,
   433→                      locales: [...trans.locales, { code: localeCode, value: '' }],
   434→                    };
   435→                  }
   436→                }
   437→                return trans;
   438→              }),
   439→            };
   440→          });
   441→        }
   442→
   443→        const [current, ...rest] = path;
   444→        return components.map(comp => {
   445→          if (comp.name !== current) return comp;
   446→
   447→          return {
   448→            ...comp,
   449→            components: comp.components ? addLocaleInComponents(comp.components, rest) : undefined,
   450→            translations: rest.length === 0 && comp.translations
   451→              ? comp.translations.map(trans => {
   452→                  if (trans.name === translationName) {
   453→                    const hasLocale = trans.locales.some(l => l.code === localeCode);
   454→                    if (!hasLocale) {
   455→                      return {
   456→                        ...trans,
   457→                        locales: [...trans.locales, { code: localeCode, value: '' }],
   458→                      };
   459→                    }
   460→                  }
   461→                  return trans;
   462→                })
   463→              : comp.translations,
   464→          };
   465→        });
   466→      };
   467→
   468→      return {
   469→        ...prev,
   470→        components: addLocaleInComponents(prev.components, componentPath),
   471→      };
   472→    });
   473→  };
   474→
   475→  const handleSave = async () => {
   476→    if (!unifiedTranslations) return;
   477→
   478→    setSaving(true);
   479→    setError('');
   480→    try {
   481→      const translationsByLocale = splitByLocale(unifiedTranslations);
   482→      
   483→      await Promise.all(
   484→        Array.from(translationsByLocale.entries()).map(async ([locale, translations]) => {
   485→          try {
   486→            await apiClient.updateTranslations(locale, {
   487→              ...translations,
   488→              version: (translations.version || 1) + 1,
   489→            });
   490→          } catch (err) {
   491→            console.error(`Failed to save translations for locale ${locale}:`, err);
   492→            throw err;
   493→          }
   494→        })
   495→      );
   496→      alert('Translations saved successfully!');
   497→    } catch (err) {
   498→      setError(
   499→        err instanceof Error ? err.message : 'Failed to save translations',
   500→      );
   501→    } finally {
   502→      setSaving(false);
   503→    }
   504→  };
   505→
   506→  const handleCreateApplication = async () => {
   507→    if (!newAppName.trim() || availableLocales.length === 0) return;
   508→
   509→    setSaving(true);
   510→    setError('');
   511→    try {
   512→      const defaultLocale = availableLocales[0];
   513→      const newApp = await apiClient.createApplication(defaultLocale, newAppName.trim());
   514→      setUnifiedTranslations(newApp);
   515→      setApplicationName(newAppName.trim());
   516→      setNewAppName('');
   517→      setCreateAppDialogOpen(false);
   518→      await loadApplications();
   519→      await loadTranslations();
   520→      alert('Application created successfully!');
   521→    } catch (err) {
   522→      setError(
   523→        err instanceof Error ? err.message : 'Failed to create application',
   524→      );
   525→    } finally {
   526→      setSaving(false);
   527→    }
   528→  };
   529→
   530→  const handleCreateComponent = () => {
   531→    if (!unifiedTranslations || !newComponentName.trim()) return;
   532→
   533→    const addComponent = (components: TranslationComponent[], path: string[]): TranslationComponent[] => {
   534→      if (path.length === 0) {
   535→        return [
   536→          ...components,
   537→          {
   538→            name: newComponentName.trim(),
   539→            description: newComponentDescription.trim() || undefined,
   540→            components: [],
   541→            translations: [],
   542→          },
   543→        ];
   544→      }
   545→
   546→      const [current, ...rest] = path;
   547→      return components.map((comp) => {
   548→        if (comp.name === current) {
   549→          return {
   550→            ...comp,
   551→            components: addComponent(comp.components || [], rest),
   552→          };
   553→        }
   554→        return comp;
   555→      });
   556→    };
   557→
   558→    setUnifiedTranslations((prev) => {
   559→      if (!prev) return prev;
   560→      return {
   561→        ...prev,
   562→        components: addComponent(prev.components, newComponentPath),
   563→      };
   564→    });
   565→
   566→    setNewComponentName('');
   567→    setNewComponentDescription('');
   568→    setNewComponentPath([]);
   569→    setCreateComponentDialogOpen(false);
   570→  };
   571→
   572→  const handleCreateTranslation = () => {
   573→    if (!unifiedTranslations || !newTranslationName.trim() || selectedLocales.length === 0) return;
   574→
   575→    const addTranslationToPath = (
   576→      components: TranslationComponent[],
   577→      path: string[],
   578→    ): TranslationComponent[] => {
   579→      if (path.length === 0) {
   580→        return components.map((comp) => {
   581→          const existingTrans = comp.translations?.find(t => t.name === newTranslationName.trim());
   582→          if (existingTrans) {
   583→            // Add missing locales to existing translation
   584→            const updatedLocales = [...existingTrans.locales];
   585→            selectedLocales.forEach(locale => {
   586→              if (!updatedLocales.some(l => l.code === locale)) {
   587→                updatedLocales.push({ code: locale, value: '' });
   588→              }
   589→            });
   590→            return {
   591→              ...comp,
   592→              translations: comp.translations?.map(t => 
   593→                t.name === newTranslationName.trim()
   594→                  ? { ...t, locales: updatedLocales }
   595→                  : t
   596→              ) || [],
   597→            };
   598→          }
   599→          return {
   600→            ...comp,
   601→            translations: [
   602→              ...(comp.translations || []),
   603→              {
   604→                name: newTranslationName.trim(),
   605→                description: newTranslationDescription.trim() || undefined,
   606→                version: 1,
   607→                locales: selectedLocales.map(locale => ({ code: locale, value: '' })),
   608→              },
   609→            ],
   610→          };
