    12→
    13→export class TranslationsMapper {
    14→  constructor(private readonly translations: TranslationsModel) {}
    15→
    16→  /**
    17→   * Maps the nested translation structure to a flat dot-notation object
    18→   * @param locale - BCP-47 locale code (e.g., 'en', 'en-US', 'ru')
    19→   * @returns Record with keys like "applicationName.component.subcomponent.translationName"
    20→   */
    21→  mapToFlatObject(locale: string): Record<string, string> {
    22→    const result: Record<string, string> = {};
    23→
    24→    const processComponent = (
    25→      component: TranslationComponentDto,
    26→      path: string[],
    27→    ): void => {
    28→      const currentPath = [...path, component.name];
    29→
    30→      // Process translations in this component
    31→      if (component.translations) {
    32→        for (const translation of component.translations) {
    33→          const localeItem = translation.locales.find(
    34→            (loc) => loc.code === locale,
    35→          );
    36→          if (localeItem) {
    37→            const key = [
    38→              this.translations.applicationName,
    39→              ...currentPath,
    40→              translation.name,
    41→            ].join('.');
    42→            result[key] = localeItem.value;
    43→          }
    44→        }
    45→      }
    46→
    47→      // Recursively process nested components
    48→      if (component.components) {
    49→        for (const nestedComponent of component.components) {
    50→          processComponent(nestedComponent, currentPath);
    51→        }
    52→      }
    53→    };
    54→
    55→    // Process all root components
    56→    for (const component of this.translations.components) {
    57→      processComponent(component, []);
    58→    }
    59→
    60→    return result;
    61→  }
    62→
    63→  /**
    64→   * Gets all translation items that have a translation for the specified locale
    65→   * @param locale - BCP-47 locale code
    66→   * @returns Array of TranslationItem that have a translation for the locale
    67→   */
    68→  getAllTranslationsByLocale(locale: string): TranslationItemDto[] {
    69→    const result: TranslationItemDto[] = [];
    70→
    71→    const processComponent = (component: TranslationComponentDto): void => {
    72→      if (component.translations) {
    73→        for (const translation of component.translations) {
    74→          if (translation.locales.some((loc) => loc.code === locale)) {
    75→            result.push(translation);
    76→          }
    77→        }
    78→      }
    79→
    80→      if (component.components) {
    81→        for (const nestedComponent of component.components) {
    82→          processComponent(nestedComponent);
    83→        }
    84→      }
    85→    };
    86→
    87→    for (const component of this.translations.components) {
    88→      processComponent(component);
    89→    }
    90→
    91→    return result;
    92→  }
    93→
    94→  /**
    95→   * Gets a specific translation value by path and locale
    96→   * @param path - Dot-separated path (e.g., "sidebar.menu.item1")
    97→   * @param locale - BCP-47 locale code
    98→   * @returns Translation value or undefined if not found
    99→   */
   100→  getTranslation(path: string, locale: string): string | undefined {
   101→    const flatObject = this.mapToFlatObject(locale);
   102→    const fullPath = `${this.translations.applicationName}.${path}`;
   103→    return flatObject[fullPath];
   104→  }
   105→}
